var e=[{id:`L3_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`진짜 짜증나게 구네……!`,JPN:`まったくイライラさせてくれる……！`,ENG:`Ugh...! They're so annoying...!`,TWN:`真會找麻煩……！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`이까짓 장난감들은 빠르게 돌파해 버리면 그만이야!`,JPN:`こんなオモチャは素早く突破しちゃえば問題ない！`,ENG:`We just have to make it through these toys!`,TWN:`等我搞定這些玩具他們就完蛋了！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`이, 이게 뭐야? 발에 다 들러붙었어!`,JPN:`な、何だこれ？　足にくっついた！`,ENG:`H-huh?! My feet are stuck to something!`,TWN:`這…這是什麼？整個都黏到腳上！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`끈끈이 덫이다! 실제로는 처음 봐!`,JPN:`とりもちだ！　実際に見るのは初めて！`,ENG:`It's a sticky trap! I've never seen one in real life before!`,TWN:`黏黏的是陷阱！第一次看到！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`누가 나 좀 잡아……`,JPN:`誰か、ちょっと引っ張って……`,ENG:`Someone grab me pleas─`,TWN:`誰來拉我一把……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`저기 공 날아온다!`,JPN:`ボールが飛んでくるよ！`,ENG:`Watch out for those balls!`,TWN:`有球飛過來！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`으악!`,JPN:`わあっ！`,ENG:`Ack!`,TWN:`呃啊！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`씨이, 이건 또 뭔데!! 사람 놀리냐?!`,JPN:`くそ、こりゃ何なんだよ！！　おちょくってんのか！？`,ENG:`Grr...! What the heck was that?! Is this some sick joke?!`,TWN:`該死，這又是怎樣！！耍人嗎？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`크으. 역시 헤이븐 형님! 어설픈 잔재주는 통하지 않아!`,JPN:`くぅ。さすがヘイブン兄貴！　生半可な小細工は通じないね！`,ENG:`Khhh. Mr. Haven strikes again! He sees right through your clumsy tricks!`,TWN:`唔，不愧是天堂大哥！小聰明是行不通的！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`감탄만 하지 말고 나 좀 여기서 떼어내 줘!`,JPN:`感心してないで早く私をここから剝がしてよ！`,ENG:`Stop admiring his work and help me out of this mess!`,TWN:`現在不是讚嘆的時候，趕快把我弄出去！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`알았어, 알았다고.`,JPN:`わかった、わかったって。`,ENG:`Okay, fine.`,TWN:`好好好。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`왜 경비가 없나 했더니만, 이런 함정이 숨겨져 있을 줄이야.`,JPN:`警備がいないと思ったら、こんな罠が隠されてたなんてね。`,ENG:`Now we know why security's so low here. Who knew there would be so many booby traps?`,TWN:`才在想說怎麼沒有人看著，原來是有陷阱！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`대체 우리 형님은 어디까지 내다 보신 거지?`,JPN:`いったい兄貴はどこまで見通してたんだろう？`,ENG:`I mean, how many steps ahead could he have planned for?`,TWN:`我們大哥到底會做到什麼程度呢？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`그냥 방탈출 게임 같은 데 썼던 어트랙션 같은데… 대충 치워 두고 잊어 버린 거 아닐까?`,JPN:`単に脱出ゲームとかで使った備品みたいだけど……適当に片付けて忘れてたんじゃないかな？`,ENG:`I think they're just attractions used in the escape room games... Maybe he forgot to clean up after putting them here?`,TWN:`感覺像是玩密室逃脫時用過的道具…是不是沒收拾乾淨，忘在這裡啦？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`또 또 답답한 소리하네, 얘는.`,JPN:`またまた、わかってないな。こいつ。`,ENG:`Ugh, you really don't know him, do you?`,TWN:`你又來，又在說這些有的沒的。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`겉모습만 따라하면 안 된다니까, 겉모습만. 형님에 대해 마음 속 깊은 곳까지 공명하라고.`,JPN:`外見だけマネしてもダメなんだって。兄貴と心の奥深いところまで共鳴し合わないと。`,ENG:`Like I said, it's not enough just imitating his style. You need to learn how he thinks and acts.`,TWN:`就跟你說不能只模仿外表，要連內心深處也對大哥有認同感好嗎！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};